import{_ as a,o,c as t,ae as i}from"./chunks/framework.Czhw_PXq.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"releases/1.8.2.md","filePath":"releases/1.8.2.md"}'),n={name:"releases/1.8.2.md"};function r(s,e,d,l,c,h){return o(),t("div",null,[...e[0]||(e[0]=[i('<h3 id="highlights" tabindex="-1">Highlights <a class="header-anchor" href="#highlights" aria-label="Permalink to &quot;Highlights&quot;">​</a></h3><p>This release finishes the language-support rollout that <code>1.8.0</code> and <code>1.8.1</code> started. Frontend labels now follow Obsidian&#39;s language selection across the shipped UI locale catalog much more consistently, including advanced settings, provider/task-language controls, diagnostics, concept-note settings, and quick-workflow surfaces that previously could still leak English after update.</p><p>It also brings the documentation back into line with the code. The remaining translated README variants were aligned against the original English README in one pass, including language-support architecture, configuration details, and troubleshooting sections. Release safety is tighter too: Notemd now gates locale coverage, translated README English leakage, hardcoded UI strings, and tooling isolation around <code>ref/**</code> before shipping.</p><h3 id="breaking-changes" tabindex="-1">Breaking Changes <a class="header-anchor" href="#breaking-changes" aria-label="Permalink to &quot;Breaking Changes&quot;">​</a></h3><ul><li><strong>No user-facing migration is required</strong>: Existing installations keep their current behavior. <code>uiLocale: auto</code> still follows Obsidian, and existing task-language settings continue to work without manual reconfiguration.</li></ul><h3 id="new-features" tabindex="-1">New Features <a class="header-anchor" href="#new-features" aria-label="Permalink to &quot;New Features&quot;">​</a></h3><ul><li><code>feat</code>: Expanded shipped UI locale coverage for frontend settings/sidebar/runtime copy so supported Obsidian locales resolve more surfaces without falling back to English.</li><li><code>feat</code>: Added audit coverage for translated README English leakage and tooling-isolation checks around <code>ref/**</code>.</li><li><code>feat</code>: Added or extended locale coverage tests for provider configuration, remaining settings surfaces, and i18n audit script configuration.</li><li><code>feat</code>: Preview modals can now export Mermaid, JSON Canvas, and Vega-Lite previews as <code>.png</code> in addition to <code>.svg</code>, while preserving raw artifact save flows.</li><li><code>feat</code>: Added a theme-resolution contract for preview/export so Mermaid, Canvas, and Vega-Lite previews follow the active Obsidian light/dark theme instead of staying visually locked to the wrong palette.</li><li><code>feat</code>: HTML diagram artifacts now have a dedicated fallback preview path, so <code>_diagram.html</code> outputs can open in the preview modal instead of degrading to escaped source text only.</li><li><code>feat</code>: HTML fallback previews now follow the resolved Obsidian preview theme instead of staying tied to browser/system color-scheme defaults.</li><li><code>feat</code>: Expanded the controlled Vega-Lite adapter templates so spec-first chart generation now supports <code>scatter</code>, <code>pie</code>, and <code>table</code> hints in addition to the existing cartesian chart set.</li><li><code>feat</code>: The planner now seeds preferred Vega-Lite chart templates so trend, share, comparison, and ranked-summary notes can recover <code>line</code>, <code>pie</code>, <code>scatter</code>, or <code>table</code> defaults even when the LLM omits <code>layoutHints.chartType</code>.</li></ul><h3 id="bug-fixes" tabindex="-1">Bug Fixes <a class="header-anchor" href="#bug-fixes" aria-label="Permalink to &quot;Bug Fixes&quot;">​</a></h3><ul><li><code>fix</code>: Fixed the <code>1.8.0</code> / <code>1.8.1</code> regression where parts of the frontend could still show English after upgrade even when Obsidian UI language had changed.</li><li><code>fix</code>: <code>uiLocale: auto</code> now resolves regional and script variants like <code>fr-CA</code>, <code>es-419</code>, <code>pt-PT</code>, <code>zh-Hans</code>, and <code>zh-Hant-HK</code> onto the nearest shipped locale instead of dropping to English.</li><li><code>fix</code>: Closed remaining untranslated labels in advanced language settings, retry/diagnostic controls, concept-note output settings, translation settings, and quick-workflow UI surfaces.</li><li><code>fix</code>: Aligned the remaining published README translations with the original English README, including troubleshooting and language-support sections.</li><li><code>fix</code>: Removed hardcoded light/dark preview chrome so iframe fallback previews, Mermaid rendering, JSON Canvas rendering, and Vega-Lite export snapshots align with the resolved Obsidian theme more reliably.</li><li><code>fix</code>: Generated Mermaid artifacts are validated before they enter preview/export flows, so parser failures surface earlier instead of leaking invalid diagrams deeper into the pipeline.</li></ul><h3 id="refactors-and-chores" tabindex="-1">Refactors And Chores <a class="header-anchor" href="#refactors-and-chores" aria-label="Permalink to &quot;Refactors And Chores&quot;">​</a></h3><ul><li><code>refactor</code>: Consolidated additional locale strings into shared locale-extension catalogs and kept the core locale catalogs synchronized.</li><li><code>chore</code>: Hardened TypeScript/Jest/audit isolation so the local reference repository under <code>ref/**</code> does not pollute normal build and test scopes.</li><li><code>docs</code>: Updated README versioning and multilingual language-support docs to match the current shipped implementation.</li></ul><h3 id="contributors" tabindex="-1">Contributors <a class="header-anchor" href="#contributors" aria-label="Permalink to &quot;Contributors&quot;">​</a></h3><p>Thanks to <code>@Jacobinwwey</code> for driving the locale-coverage completion, README alignment, and verification-gate hardening for this release.</p>',13)])])}const p=a(n,[["render",r]]);export{u as __pageData,p as default};
